const express = require('express');
const app = express();
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

// Connect to MongoDB
mongoose.connect('mongodb://localhost/gameDB', { useNewUrlParser: true, useUnifiedTopology: true });

// Define schema for user data
const userSchema = new mongoose.Schema({
    username: String,
    password: String,
    levelsCompleted: [{ type: Number, score: Number, time: Number }]
});

// Create model from schema
const User = mongoose.model('User', userSchema);

// Middleware to parse JSON requests
app.use(express.json());

// Endpoint for completing a level
app.post('/completeLevel', async (req, res) => {
    try {
        const { username, score, time } = req.body;
        const existingUser = await User.findOne({ username });
        
        if (!existingUser) {
            const newUser = new User({
                username,
                levelsCompleted: [{ score, time }]
            });
            await newUser.save();
            res.json({ message: 'New user created' });
        } else {
            existingUser.levelsCompleted.push({ score, time });
            await existingUser.save();
            res.json({ message: 'Level completed' });
        }
    } catch (err) {
        console.error(err);
        res.status(500).json({ message: 'Error completing level' });
    }
});

// Endpoint for claiming rewards
app.post('/claimRewards', async (req, res) => {
    try {
        const { username } = req.body;
        const user = await User.findOne({ username });
        
        if (!user) {
            return res.status(404).json({ message: 'User not found' });
        }
        
        // Award rewards based on client-reported metrics
        const rewardLevel = 3; // Example reward level
        const rewardScore = 1000; // Example reward score
        
        if (user.levelsCompleted.length >= rewardLevel) {
            user.levelsCompleted.splice(0, rewardLevel);
            await user.save();
            res.json({ message: `Rewards claimed for ${rewardLevel} levels` });
        } else {
            res.json({ message: 'Not enough levels completed to claim rewards' });
        }
    } catch (err) {
        console.error(err);
        res.status(500).json({ message: 'Error claiming rewards' });
    }
});

// Start server
const port = 3000;
app.listen(port, () => {
    console.log(`Server listening on port ${port}`);
});